import json
import re
from typing import Any


# Step 1 — extract JSON text from LLM output that may have markdown fences
def extract_json_text(raw: str) -> str:
    """Strip ```json ... ``` or ``` ... ``` wrappers if present."""
    fence_match = re.search(
        r"```(?:json)?\s*([\s\S]*?)```", raw, re.DOTALL
    )
    if fence_match:
        return fence_match.group(1).strip()
    return raw.strip()


# Step 2 — parse, raising a descriptive error on failure
def parse_json(text: str) -> Any:
    """Parse JSON text. Raises ValueError with context on failure."""
    try:
        return json.loads(text)
    except json.JSONDecodeError as exc:
        snippet = text[:120].replace("\n", " ")
        raise ValueError(
            f"JSON parse failed at line {exc.lineno} col {exc.colno}: "
            f"{exc.msg}\nSnippet: {snippet!r}"
        ) from exc


# Step 3 — validate the expected shape (without Pydantic)
def validate_tool_call(data: Any) -> dict:
    """Ensure the parsed value is a dict with 'name' and 'arguments'."""
    if not isinstance(data, dict):
        raise TypeError(f"Expected JSON object, got {type(data).__name__}")
    if "name" not in data:
        raise KeyError("Missing required key 'name' in tool call")
    if not isinstance(data.get("arguments"), dict):
        raise TypeError("'arguments' must be a JSON object")
    return data


# Composed pipeline
def parse_tool_call(raw_llm_output: str) -> dict:
    text = extract_json_text(raw_llm_output)
    data = parse_json(text)
    return validate_tool_call(data)


# Usage
sample = """```json
{"name": "search_web", "arguments": {"query": "agentic AI 2024"}}
```"""

tool_call = parse_tool_call(sample)
print(tool_call["name"])          # search_web
print(tool_call["arguments"])     # {'query': 'agentic AI 2024'}

import json
from datetime import datetime, timezone
from decimal import Decimal


def agent_json_encoder(obj):
    """Custom encoder for types json.dumps cannot handle natively."""
    if isinstance(obj, datetime):
        return obj.isoformat()
    if isinstance(obj, Decimal):
        # Preserve precision as string rather than float
        return str(obj)
    if isinstance(obj, bytes):
        import base64
        return base64.b64encode(obj).decode("ascii")
    if isinstance(obj, set):
        return sorted(obj)        # deterministic serialization
    raise TypeError(f"Object of type {type(obj).__name__} is not JSON serializable")


def serialize_agent_result(result: dict) -> str:
    """Serialize an agent result to a compact JSON string."""
    return json.dumps(result, ensure_ascii=False, default=agent_json_encoder)


