// Parse an LLM tool-call response safely
function parseToolCall(raw) {
  // Strip markdown fences if present
  const fenceMatch = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
  const text = fenceMatch ? fenceMatch[1].trim() : raw.trim();

  let data;
  try {
    data = JSON.parse(text);
  } catch (err) {
    throw new Error(`JSON parse failed: ${err.message}\nInput: ${text.slice(0, 80)}`);
  }

  if (typeof data !== "object" || data === null || Array.isArray(data)) {
    throw new TypeError(`Expected JSON object, got ${Array.isArray(data) ? "array" : typeof data}`);
  }
  if (!data.name || typeof data.arguments !== "object") {
    throw new Error("Invalid tool call structure");
  }
  return data;
}

