import json
import re
from datetime import datetime, timezone
from typing import Any


class ToolCallParser:
    """Parses and logs LLM-generated tool calls at agent boundaries."""

    FENCE_RE = re.compile(r"```(?:json)?\s*([\s\S]*?)```", re.DOTALL)

    def __init__(self, trace_path: str):
        self._trace = open(trace_path, "a", encoding="utf-8")

    def _log(self, level: str, **kwargs):
        record = {"ts": datetime.now(timezone.utc).isoformat(), "level": level, **kwargs}
        self._trace.write(json.dumps(record, ensure_ascii=False) + "\n")
        self._trace.flush()

    def parse(self, raw: str) -> dict:
        # 1. Strip markdown fences
        m = self.FENCE_RE.search(raw)
        text = m.group(1).strip() if m else raw.strip()

        # 2. Parse
        try:
            data = json.loads(text)
        except json.JSONDecodeError as exc:
            self._log("error", phase="parse", msg=str(exc), raw_snippet=text[:200])
            raise

        # 3. Light validation — full schema validation done by Pydantic layer above
        if not isinstance(data, dict) or "name" not in data:
            self._log("error", phase="validate", msg="bad shape", parsed=repr(data)[:200])
            raise ValueError("Tool call must be a JSON object with 'name'")

        self._log("info", phase="ok", tool=data["name"])
        return data

    def serialize_result(self, result: Any) -> str:
        """Compact JSON string for the HTTP response body."""
        return json.dumps(result, ensure_ascii=False, separators=(",", ":"))

    def close(self):
        self._trace.close()


# --- Integration point ---
parser = ToolCallParser("/tmp/run_trace.jsonl")

raw_llm = """
The model returns a tool call like this:
```json
{
  "name": "search_web",
  "arguments": {"query": "renewable energy 2025", "limit": 3}
}
```
"""

tool = parser.parse(raw_llm)
# ... dispatch tool, get result ...
