# Or enforce depth manually before parsing if on older Python:
def count_depth(s: str, limit: int = 50) -> None:
    depth = 0
    for ch in s:
        if ch in "{[":
            depth += 1
            if depth > limit:
                raise ValueError(f"JSON nesting exceeds limit of {limit}")
        elif ch in "}]":
            depth -= 1
